import React, { useState } from 'react';
import {useQuery} from '@tanstack/react-query'
import '../HomePage/home.scss';
import { fetchMovie } from '../../utils/fetchApi';
const Home = () => {
  const Img_URL="https://image.tmdb.org/t/p/original/";

  const [Movie,setMovies]=useState([]);
  const {isError,isLoading,error,data} =useQuery({
    queryKey:['Movie','Upcoming'],
    queryFn:()=> fetchMovie('upcoming')
    .then((res)=> {
      setMovies(res.results);
      return res.results}),
  });

  const Toprated=useQuery({
    queryKey:['Movie','Toprated'],
    queryFn:()=> fetchMovie('toprated')
    .then((res)=>{
      return res.results
    }), 
  })

  console.log(Toprated?.data);
  // console.log(data,Movie);

if(isLoading){
  return <div className='loading'><h1>Loading</h1></div>
}else if(isError){
  return <div className='error'><p>{error.message}</p></div>
}
  return (
    <section className='home'>
      <div className='banner' style={{backgroundImage:data?`url(${`${Img_URL}${data[4].backdrop_path}`})`:"rgb(0,0,0)"}}>

      </div>
    </section>
  )
}

export default Home
